        assertEquals(2005, c.get(Calendar.YEAR));
        assertEquals(Calendar.MAY, c.get(Calendar.MONTH));
        assertEquals(25, c.get(Calendar.DAY_OF_MONTH));



        result = MAPPER.readerFor(DateAsStringBean.class)
                .with(Locale.GERMANY)
