      JsonParser parser = mapper.getFactory().createParser(json);
      parser.setCodec(new ObjectMapper());
      try {
          parser.readValueAsTree();
      } catch(JsonParseException e) {
          verifyException(e, "Unexpected end-of-input");
      }
      parser.close();

